html:div.style:
margin: 1em 0 1em 0.25em;
padding: 0.5em 1.1em 0.5em 1.2em;
border-left: 4px solid rgba(200, 55, 45, 0.85);
border-radius: var(--radius);
background-color: rgba(200, 55, 45, 0.06);

margin: 1em 0 1em 0.25em;
padding: 0.5em 1.1em 0.5em 1.2em;
border-left: 4px solid rgba(40, 150, 80, 0.9);
border-radius: var(--radius);
background-color: rgba(40, 150, 80, 0.06);

fr:mainmatter.html:pre:
acquire(lock_ptr):
  while (true):
    // Perform "test-and-set"
    // UNLOCKED = 0, LOCKED = 1
    test_and_set(old, lock_ptr)
    if (old == UNLOCKED):
      break // lock acquired!
    // keep spinning, back to top of while loop

release(lock_ptr):
  store[lock_ptr] <- UNLOCKED

html:div.style:
margin: 1em 0 1em 0.25em;
padding: 0.5em 1.1em 0.5em 1.2em;
border-left: 4px solid rgba(200, 55, 45, 0.85);
border-radius: var(--radius);
background-color: rgba(200, 55, 45, 0.06);

fr:mainmatter.html:pre:
acquire(lock_ptr):
  while (true):
    // Perform "test"
    load [lock_ptr] -> original_value
    if (original_value == UNLOCKED):
      // Perform "test-and-set"
      test_and_set(old, lock_ptr)
      if (old == UNLOCKED):
        break // lock acquired!
    // keep spinning, back to top of while loop

release(lock_ptr):
  store[lock_ptr] <- UNLOCKED

